1.Record避免繁琐的DTO语法、JAVA16+支持、用于少业务逻辑、单纯做数据存储。数据比对时可以重写equal,选择要比对的值，默认全属性比对，再重写hashcode，避免报错 Student实体import java.time.LocalDate; // record 自动生成构造器、equals、hashCode、toString public record Student ( String id, //学号 String name,// 姓名 int age,// 年龄 String grade,// 年级 LocalDate enrollDate // 入学时间 )&#123; // 可以添加自定义方法 public boolean isAdult() &#123; return age &gt;= 18; &#125; //紧凑构造器，用于验证 public Student &#123; if(id==null || id.isBlank())&#123; throw new IllegalArgumentException(&quot;学号不能为空&quot;); &#125; if(name==null || name.isBlank())&#123; throw new IllegalArgumentException(&quot;姓名不能为空&quot;); &#125; if(age&lt;0)&#123; throw new IllegalArgumentException(&quot;年龄不能小于0&quot;); &#125; if(age&gt;150)&#123; throw new IllegalArgumentException(&quot;年龄不能大于150&quot;); &#125; &#125; &#125; 学生Serviceimport java.util.*; import java.util.stream.Collectors; public class StudentService &#123; private final List&lt;Student&gt; students = new ArrayList&lt;&gt;(); //添加学生 public boolean addStudent(Student student) &#123; boolean exists = students.stream().anyMatch(s -&gt; s.id().equals(student.id())); if (exists) &#123; System.out.println(&quot;该学生已存在，学号为：&quot; + student.id()); return false; &#125; students.add(student); System.out.println(&quot;添加成功&quot; + student.name()); return true; &#125; //删除学生 public boolean deleteStudent(String id) &#123; boolean removed = students.removeIf(s -&gt; s.id().equals(id)); if (removed) &#123; System.out.println(&quot;删除成功，学号为：&quot; + id); &#125; else &#123; System.out.println(&quot;该学生不存在，学号为：&quot; + id); &#125; return removed; &#125; //更新学生信息 public boolean updateStudent(String id, String newName, Integer newAge) &#123; for (int i = 0; i &lt; students.size(); i++) &#123; Student s = students.get(i); if (s.id().equals(id)) &#123; Student updated = new Student( s.id(), newName != null ? newName : s.name(), newAge != null ? newAge : s.age(), s.grade(), s.enrollDate() ); students.set(i, updated); System.out.println(&quot;更新成功，学号为：&quot; + id); return true; &#125; &#125; System.out.println(&quot;该学生不存在，学号为：&quot; + id); return false; &#125; //查询学生按学号 public Optional&lt;Student&gt; findById(String id) &#123; return students.stream() .filter(s -&gt; s.id().equals(id)) .findFirst(); &#125; //查询学生按姓名 public List&lt;Student&gt; findByName(String name) &#123; return students.stream() .filter(s -&gt; s.name().equalsIgnoreCase(name)) .toList(); &#125; //查询学生按年级 public List&lt;Student&gt; findByGrade(String grade) &#123; return students.stream() .filter(s -&gt; s.grade().equals(grade)) .toList(); &#125; //查询所有学生 public List&lt;Student&gt; findAll() &#123; return new ArrayList&lt;&gt;(students);//返回副本，保护内部数据 &#125; //查询所有学生按年龄排序 public List&lt;Student&gt; sortByAge() &#123; return students.stream() .sorted(Comparator.comparing(Student::age)) .toList(); &#125; // 统计成年学生 public long countAdults() &#123; return students.stream() .filter(Student::isAdult) .count(); &#125; // 获取所有年级 public Set&lt;String&gt; getAllGrades() &#123; return students.stream() .map(Student::grade) .collect(Collectors.toSet()); &#125; &#125; 主程序import java.time.LocalDate; import java.util.List; public class Main &#123; public static void main(String[] args) &#123; StudentService service = new StudentService(); System.out.println(&quot;=== 学生管理系统 ===\n&quot;); // 1. 添加学生 System.out.println(&quot;--- 添加学生 ---&quot;); Student s1 = new Student(&quot;001&quot;, &quot;张三&quot;, 18, &quot;大一&quot;, LocalDate.of(2024, 9, 1)); System.out.println(&quot;添加成功: &quot; + s1); Student s2 = new Student(&quot;002&quot;, &quot;李四&quot;, 20, &quot;大二&quot;, LocalDate.of(2023, 9, 1)); Student s3 = new Student(&quot;003&quot;, &quot;王五&quot;, 17, &quot;大一&quot;, LocalDate.of(2024, 9, 1)); Student s4 = new Student(&quot;004&quot;, &quot;赵六&quot;, 22, &quot;大三&quot;, LocalDate.of(2022, 9, 1)); service.addStudent(s1); service.addStudent(s2); service.addStudent(s3); service.addStudent(s4); // 测试重复学号 service.addStudent(new Student(&quot;001&quot;, &quot;重复&quot;, 20, &quot;大四&quot;, LocalDate.now())); System.out.println(); // 2. 查询所有学生 System.out.println(&quot;--- 所有学生 ---&quot;); service.findAll().forEach(System.out::println); System.out.println(); // 3. 按学号查询 System.out.println(&quot;--- 按学号查询 ---&quot;); service.findById(&quot;002&quot;).ifPresentOrElse( s -&gt; System.out.println(&quot;找到: &quot; + s), () -&gt; System.out.println(&quot;未找到&quot;) ); System.out.println(); // 4. 按姓名查询 System.out.println(&quot;--- 按姓名查询 ---&quot;); List&lt;Student&gt; result = service.findByName(&quot;张三&quot;); result.forEach(System.out::println); System.out.println(); // 5. 按年级查询 System.out.println(&quot;--- 按年级查询 ---&quot;); service.findByGrade(&quot;大一&quot;).forEach(System.out::println); System.out.println(); // 6. 更新学生 System.out.println(&quot;--- 更新学生 ---&quot;); service.updateStudent(&quot;003&quot;, &quot;王五改&quot;, 18); System.out.println(&quot;更新后: &quot; + service.findById(&quot;003&quot;).get()); System.out.println(); // 7. 删除学生 System.out.println(&quot;--- 删除学生 ---&quot;); service.deleteStudent(&quot;004&quot;); System.out.println(); // 8. 按年龄排序 System.out.println(&quot;--- 按年龄排序 ---&quot;); service.sortByAge().forEach(System.out::println); System.out.println(); // 9. 统计数据 System.out.println(&quot;--- 统计信息 ---&quot;); System.out.println(&quot;成年学生数: &quot; + service.countAdults()); System.out.println(&quot;所有年级: &quot; + service.getAllGrades()); System.out.println(); // 10. 最终学生列表 System.out.println(&quot;--- 最终学生列表 ---&quot;); service.findAll().forEach(System.out::println); &#125; &#125;
IOC（控制反转、Spring、DI）IOC是思想, DI是实现方式 ,将自己可以new的对象交给容器管理 ,容器在我们需要对象的时候DI作用：
对象之间的耦合度或者说依赖程度降低。 资源变的容易管理；比如你用 Spring 容器提供的话很容易就可以实现一个单例。
IoC 容器容器就是存放和管理 Bean 的地方 Bean 的作用域
作用域 说明 使用场景
singleton（默认） 整个容器只有一个实例 无状态服务
prototype 每次获取都创建新实例 有状态对象
request（Web） 每个请求一个实例 Web应用
session（Web） 每个会话一个实例 用户会话
@Component@Scope(&quot;prototype&quot;) // 每次都是新对象public class ShoppingCart &#123; private List&lt;Item&gt; items = new ArrayList&lt;&gt;();&#125;@Component@Scope(&quot;singleton&quot;) // 默认，整个应用只有一个,可不写public class Calculator &#123; public int add(int a, int b) &#123; return a + b; &#125;&#125; 三种依赖注入: 1️⃣ 字段注入（最常用）
@Component //UserDao @Component(&quot;alipay&quot;) // 自定义名称public class UserService &#123; @Autowired @Qualifier(&quot;alipay&quot;) // 使用自定义名称 private UserDao userDao; // 直接注入 @Autowired private EmailService emailService;&#125;
2️⃣ 构造器注入（推荐，官方推荐）
@Component public class UserService &#123; private final UserDao userDao; private final EmailService emailService; // 不用写 @Autowired，Spring 自动识别 public UserService(UserDao userDao, EmailService emailService) &#123; this.userDao = userDao; this.emailService = emailService; &#125;&#125;
3️⃣ Setter 注入（用于可选依赖）
@Componentpublic class UserService &#123; private UserDao userDao; @Autowired public void setUserDao(UserDao userDao) &#123; this.userDao = userDao; &#125;&#125; 核心注解详解1. @Component - 将类标记为 Bean@Component // 最通用public class CommonService &#123;&#125;@Repository // 数据访问层@Primary //当没有 @Qualifier 时，默认注入这个public class UserDao &#123;&#125;@Service // 业务逻辑层public class UserService &#123;&#125;@Controller // Web 控制层public class UserController &#123;&#125;// 它们本质上都是 @Component，只是语义不同
2. @Autowired - 自动注入依赖@Componentpublic class OrderService &#123; // 按类型注入 @Autowired private PaymentService paymentService; // 如果有多个同类型，可以用 @Qualifier 指定名称 注意：@Qualifier 的值默认是**类名首字母小写** @Autowired @Qualifier(&quot;alipay&quot;) private PaymentService paymentService; // 可选依赖（找不到就不注入） @Autowired(required = false) private Logger logger;&#125; 3. @Configuration - 配置类@Configuration // 标记为配置类public class AppConfig &#123; // 手动注册 Bean @Bean public DataSource dataSource() &#123; HikariDataSource ds = new HikariDataSource(); ds.setJdbcUrl(&quot;jdbc:mysql://localhost:3306/test&quot;); ds.setUsername(&quot;root&quot;); ds.setPassword(&quot;123456&quot;); return ds; &#125; @Bean public UserService userService() &#123; // 可以调用其他 @Bean 方法 return new UserService(userDao()); &#125; @Bean public UserDao userDao() &#123; return new UserDao(dataSource()); &#125;&#125; 4. @Value - 注入配置值@Componentpublic class AppProperties &#123; @Value(&quot;$&#123;app.name&#125;&quot;) private String appName; // 从配置文件读取 @Value(&quot;$&#123;server.port:8080&#125;&quot;) private int port; // 默认值 8080 @Value(&quot;10&quot;) private int timeout; // 直接赋值 @Value(&quot;#&#123;systemProperties[&#x27;user.home&#x27;]&#125;&quot;) private String userHome; // SpEL 表达式&#125; application.ymlapp: name: MySpringAppserver: port: 9000 真实项目中的典型用法@Configurationpublic class PaymentConfig &#123; @Bean @Qualifier(&quot;alipay&quot;) public PaymentService alipayPayment() &#123; return new AlipayService(); &#125; @Bean @Qualifier(&quot;wechat&quot;) public PaymentService wechatPayment() &#123; return new WechatPayService(); &#125;&#125; @Servicepublic class PaymentProcessor &#123; private final Map&lt;String, PaymentService&gt; paymentServiceMap; // 构造器注入所有 PaymentService，并放到 Map 中 public PaymentProcessor(Map&lt;String, PaymentService&gt; paymentServiceMap) &#123; this.paymentServiceMap = paymentServiceMap; &#125; public void process(String channel, BigDecimal amount) &#123; PaymentService service = paymentServiceMap.get(channel); if (service != null) &#123; service.pay(amount); &#125; &#125;&#125; 这样调用时：process(&quot;alipay&quot;, new BigDecimal(100)) 就能动态选择支付方式。 Aop 面向切面编程AOP（面向切面编程）的核心作用AOP 允许你将横切关注点（跨越多个模块的公共逻辑）从业务代码中抽取出来，实现关注点分离。 一、主要作用总结
作用 说明 典型场景
日志记录 统一记录方法调用、参数、返回值 审计、调试
性能监控 统计方法执行时间 慢查询排查、性能瓶颈分析
事务管理 统一管理数据库事务 增删改操作的开启&#x2F;提交&#x2F;回滚
权限校验 方法调用前检查用户权限 接口鉴权、角色验证
缓存管理 方法返回值缓存 减少数据库查询
异常处理 统一捕获和处理异常 错误日志、降级处理
参数校验 统一验证输入参数 接口入参合法性
幂等性控制 防止重复提交 表单重复提交、接口重试
二、具体代码示例1. 日志记录（最常用）@Aspect@Componentpublic class LogAspect &#123; @Around(&quot;@annotation(com.example.annotation.Log)&quot;) public Object logMethod(ProceedingJoinPoint joinPoint) throws Throwable &#123; String methodName = joinPoint.getSignature().getName(); Object[] args = joinPoint.getArgs(); System.out.println(&quot;【调用前】方法：&quot; + methodName + &quot;，参数：&quot; + Arrays.toString(args)); long start = System.currentTimeMillis(); Object result = joinPoint.proceed(); // 执行原方法 long end = System.currentTimeMillis(); System.out.println(&quot;【调用后】返回值：&quot; + result + &quot;，耗时：&quot; + (end - start) + &quot;ms&quot;); return result; &#125;&#125;
使用时只要在方法上加注解，就能自动记录日志： @Servicepublic class UserService &#123; @Log public User getUserById(Long id) &#123; // 业务代码，不需要写任何日志逻辑 return userMapper.selectById(id); &#125;&#125;
2. 事务管理@Aspect@Componentpublic class TransactionAspect &#123; @Around(&quot;@annotation(Transactional)&quot;) public Object manageTransaction(ProceedingJoinPoint joinPoint) throws Throwable &#123; try &#123; beginTransaction(); // 开启事务 Object result = joinPoint.proceed(); // 执行业务方法 commitTransaction(); // 提交事务 return result; &#125; catch (Exception e) &#123; rollbackTransaction(); // 回滚事务 throw e; &#125; &#125;&#125;
3. 性能监控@Aspect@Componentpublic class PerformanceAspect &#123; @Around(&quot;@annotation(com.example.annotation.Monitor)&quot;) public Object monitor(ProceedingJoinPoint joinPoint) throws Throwable &#123; String methodName = joinPoint.getSignature().toShortString(); long start = System.currentTimeMillis(); try &#123; return joinPoint.proceed(); &#125; finally &#123; long duration = System.currentTimeMillis() - start; if (duration &gt; 1000) &#123; // 超过1秒告警 System.out.println(&quot;【慢查询】&quot; + methodName + &quot; 耗时：&quot; + duration + &quot;ms&quot;); &#125; &#125; &#125;&#125;
4. 权限校验@Aspect@Componentpublic class AuthAspect &#123; @Before(&quot;@annotation(com.example.annotation.RequireRole)&quot;) public void checkPermission(JoinPoint joinPoint) &#123; // 从请求上下文获取当前用户角色 String userRole = getCurrentUserRole(); String requiredRole = getRequiredRole(joinPoint); if (!userRole.equals(requiredRole)) &#123; throw new SecurityException(&quot;权限不足，需要：&quot; + requiredRole); &#125; &#125;&#125;
5. 缓存管理@Aspect@Componentpublic class CacheAspect &#123; private Map&lt;String, Object&gt; cache = new ConcurrentHashMap&lt;&gt;(); @Around(&quot;@annotation(com.example.annotation.Cacheable)&quot;) public Object cacheable(ProceedingJoinPoint joinPoint) throws Throwable &#123; String key = joinPoint.getSignature().toShortString() + Arrays.toString(joinPoint.getArgs()); // 先查缓存 if (cache.containsKey(key)) &#123; System.out.println(&quot;【缓存命中】&quot; + key); return cache.get(key); &#125; // 缓存未命中，执行原方法 Object result = joinPoint.proceed(); cache.put(key, result); System.out.println(&quot;【缓存写入】&quot; + key); return result; &#125;&#125;
三、AOP 的执行时机（通知类型）
类型 注解 执行时机
前置通知 @Before 方法执行前
后置通知 @After 方法执行后（无论是否异常）
返回通知 @AfterReturning 方法正常返回后
异常通知 @AfterThrowing 方法抛出异常后
环绕通知 @Around 方法执行前后（最强大）
四、没有 AOP 的痛点// 没有 AOP 的代码：横切逻辑到处重复public User getUserById(Long id) &#123; logger.info(&quot;调用方法：getUserById，参数：&quot; + id); // 日志 startTransaction(); // 事务 try &#123; User user = userMapper.selectById(id); commitTransaction(); // 事务 logger.info(&quot;方法返回：&quot; + user); // 日志 return user; &#125; catch (Exception e) &#123; rollbackTransaction(); // 事务 logger.error(&quot;方法异常：&quot; + e.getMessage()); // 日志 throw e; &#125;&#125;public Order getOrderById(Long id) &#123; logger.info(&quot;调用方法：getOrderById，参数：&quot; + id); // 同样的代码重复 startTransaction(); // ... 又是一模一样的模板代码&#125;
使用 AOP 后，业务代码恢复纯净： @Log@Transactionalpublic User getUserById(Long id) &#123; return userMapper.selectById(id); // 只有业务逻辑&#125;
五、实际应用场景总结
场景 是否必须用 AOP 替代方案
全局日志 ✅ 强烈推荐 手动在每个方法写日志 ❌
事务管理 ✅ Spring 已内置 手动开启&#x2F;提交 ❌
权限校验 ✅ 推荐 在每个 Controller 写校验 ❌
接口限流 ✅ 推荐 手动判断 ❌
数据脱敏 ✅ 推荐 在每个 getter 处理 ❌
分布式锁 ✅ 推荐 手动加锁&#x2F;释放 ❌
一句话总结：AOP 让你不要在业务代码中重复写日志、事务、权限等样板代码，把这些公共逻辑抽到切面里统一管理，业务代码只关心核心逻辑。
